function navigateTo(viewId) {
    // 1. 모든 화면(page-view)을 숨김 처리
    document.querySelectorAll('.page-view').forEach(view => {
        view.classList.remove('active');
        view.classList.add('hidden');
    });
    
    // 2. 요청된 화면만 표시
    const targetView = document.getElementById(viewId);
    if (targetView) {
        targetView.classList.remove('hidden');
        targetView.classList.add('active');
    }

    // KCD 데이터 지연 로딩
        if (viewId === 'view-accident') {
        if(typeof initAccidentView === 'function') initAccidentView();
    }

    if (viewId === 'view-neo' && typeof loadNeoData === 'function') {
        loadNeoData();
    }

    if (viewId === 'view-surgery' && typeof initSurgeryView === 'function') {
        initSurgeryView();
    }
    if (viewId === 'view-kcd' && typeof loadKcdData === 'function') {
        loadKcdData();
    }
    if (viewId === 'view-injury-class' && typeof renderInjuryData === 'function') {
        renderInjuryData();
    }
    if (viewId === 'view-auto') {
        if (typeof initAutoCalc === 'function') initAutoCalc();
    }
}

function toggleAccordion(index) {
    const item = document.getElementById(`acc-${index}`);
    // 기존에 열려있던 다른 항목들을 닫고 싶다면 아래 주석을 해제하세요.
    // document.querySelectorAll('.accordion-item').forEach(el => {
    //     if (el.id !== `acc-${index}`) el.classList.remove('open');
    // });
    item.classList.toggle('open');
}

function switchDtTab(tabName) {
    const tabs = document.querySelectorAll('.dt-tab');
    tabs.forEach(t => t.classList.remove('active'));
    
    // 수동으로 탭 찾아서 활성화
    if (tabName === 'grades') tabs[0].classList.add('active');
    if (tabName === 'parts') tabs[1].classList.add('active');
    if (tabName === 'explanations') tabs[2].classList.add('active');

    const accordion = document.getElementById('disability-accordion');
    const partsGroup = document.getElementById('disability-parts');
    const explanations = document.getElementById('disability-explanations');

    accordion.classList.add('hidden');
    partsGroup.classList.add('hidden');
    explanations.classList.add('hidden');

    if (tabName === 'grades') {
        accordion.classList.remove('hidden');
    } else if (tabName === 'parts') {
        partsGroup.classList.remove('hidden');
    } else {
        explanations.classList.remove('hidden');
    }
}


function formatExplanationContent(content) {
    let text = Array.isArray(content) ? content.join('\n') : content;
    text = text.replace(/<br\s*\/?>/gi, '\n');
    
    // Also split by \n or any block tags if needed, but we already have newlines
    let lines = text.split('\n');
    let formatted = lines.map(line => {
        let trimmed = line.trim();
        if (!trimmed) return '';
        
        // Remove HTML entities and tags for pure text testing
        let plainText = trimmed.replace(/&nbsp;/g, ' ').replace(/<[^>]+>/g, '').trim();
        
        let pad = 0;
        let indent = 0;
        let margin = 0;
        let top = 2;
        let bottom = 2;
        
        // 1) 2) ... : Base level
        if (/^\d+\)/.test(plainText)) {
            pad = 0; indent = -24; margin = 24; top = 8;
        } 
        // ① ② ... : Level 1 indent (under numbers)
        else if (/^[①②③④⑤⑥⑦⑧⑨⑩]/.test(plainText)) {
            pad = 24; indent = -20; margin = 24;
        } 
        // 가) 나) ... : Level 2 indent
        else if (/^[가-하]\)/.test(plainText)) {
            pad = 44; indent = -20; margin = 24;
        } 
        // ㉮ ㉯ ... : Level 3 indent
        else if (/^[㉮㉯㉰㉱㉲㉳]/.test(plainText)) {
            pad = 64; indent = -20; margin = 24;
        } 
        // - : Level 1 bullet
        else if (/^-/.test(plainText)) {
            pad = 24; indent = -16; margin = 24;
        }
        // 가. 나. : Top level title
        else if (/^[가-하]\./.test(plainText)) {
            pad = 0; indent = 0; margin = 0; top = 16; bottom = 6;
        } 
        else {
            pad = 0; indent = 0; margin = 0;
        }
        
        return `<div style="display: block; padding-left: ${pad}px; text-indent: ${indent}px; margin-left: ${margin}px; margin-top: ${top}px; margin-bottom: ${bottom}px;">${trimmed}</div>`;
    });
    
    return formatted.join('');
}

function applyTooltips(text, versionId) {
    if (versionId === 'v9807_nonlife' || versionId === 'v0505_unified' || versionId === 'v1804') return text; // Disable tooltips for this version
    
    let result = text;
    let currentKeywords = tooltipKeywords;
    
    for (const [keyword, info] of Object.entries(currentKeywords)) {
        if (result.includes(keyword)) {
            // Replace only the first occurrence to avoid nested issues
            const html = `<span class="keyword-link" onclick="jumpToExp('${info.expId}')">${keyword}<span class="keyword-tooltip">${info.tooltip}<br><span style="color:#94a3b8; font-size:11px; margin-top:4px; display:block;">클릭하여 상세 해설</span></span></span>`;
            result = result.replace(keyword, html);
        }
    }
    return result;
}

function jumpToExp(expId) {
    // 1. 탭 전환
    switchDtTab('explanations');
    
    // 2. 해당 요소 찾기
    setTimeout(() => {
        const targetCard = document.getElementById(expId);
        if (targetCard) {
            // 부드럽게 스크롤
            targetCard.scrollIntoView({ behavior: 'smooth', block: 'center' });
            
            // 애니메이션 클래스 제거 후 다시 추가 (반복 클릭 대응)
            targetCard.classList.remove('exp-highlight');
            // 강제로 리플로우 발생
            void targetCard.offsetWidth; 
            targetCard.classList.add('exp-highlight');
        }
    }, 50); // 탭 전환 후 약간의 딜레이
}

function loadDisabilityTable(versionId, title) {
    const container = document.getElementById('disability-accordion');
    const expContainer = document.getElementById('disability-explanations');
    const titleEl = document.getElementById('dt-title');
    const tabs = document.getElementById('dt-tabs');
    const desc = document.getElementById('dt-desc');
    
    if (!container || !titleEl) return;
    
    // 타이틀 업데이트
    titleEl.textContent = `장해분류표 - ${title}`;
    
    const data = allDisabilityData[versionId];
    
    // Clear all containers
    const partsGroup = document.getElementById('disability-parts');
    const chongchik = document.getElementById('disability-chongchik');
    const criteria = document.getElementById('disability-criteria');
    if(partsGroup) partsGroup.classList.add('hidden');
    if(chongchik) chongchik.classList.add('hidden');
    if(criteria) criteria.classList.add('hidden');
    
    if (!data || (Array.isArray(data) && data.length === 0)) {
        // 데이터가 없는 경우
        tabs.classList.add('hidden');
        expContainer.classList.add('hidden');
        container.classList.remove('hidden');
        desc.classList.remove('hidden');
        desc.textContent = "원하시는 신체 부위를 선택하시면 상세 장해 상태와 지급률(%)을 확인하실 수 있습니다.";
        
        container.innerHTML = `
            <div style="padding: 40px; text-align: center; color: #6b7280;">
                <span class="material-icons-round" style="font-size: 48px; color: #d1d5db; margin-bottom: 16px;">construction</span>
                <br>해당 시점의 데이터는 준비 중입니다.
            </div>
        `;
    } else if (data.type === 'tab' || data.type === 'parts_only' || data.type === 'parts_and_exp') {
        const partsContainer = document.getElementById('disability-parts');
        
        if (data.type === 'parts_only') {
            tabs.classList.add('hidden'); // Hide the entire tab bar
        } else {
            tabs.classList.remove('hidden');
            const tabBtns = document.querySelectorAll('.dt-tab');
            if (data.type === 'parts_and_exp') {
                tabBtns[0].classList.add('hidden'); // Hide Grades tab
                tabBtns[1].classList.remove('hidden');
                tabBtns[1].classList.add('active'); // Activate Parts tab
                tabBtns[2].classList.remove('hidden');
                tabBtns[2].classList.remove('active');
            } else {
                tabBtns[0].classList.remove('hidden');
                tabBtns[0].classList.add('active'); // Activate Grades tab
                tabBtns[1].classList.remove('hidden');
                tabBtns[1].classList.remove('active');
                tabBtns[2].classList.remove('hidden');
                tabBtns[2].classList.remove('active');
            }
        }
        
        desc.classList.add('hidden');
        
        if (data.type === 'parts_only' || data.type === 'parts_and_exp') {
            container.classList.add('hidden');
            partsContainer.classList.remove('hidden');
            expContainer.classList.add('hidden'); // Default is parts view
        } else {
            container.classList.remove('hidden');
            partsContainer.classList.add('hidden');
            expContainer.classList.add('hidden');
        }

        // 1.

        // 1.

        // 1. 급수별 렌더링 (if tab)
        if (data.type === 'tab' && data.grades) {
            let gradesHtml = '';
            data.grades.forEach((group, index) => {
                let listHtml = '';
                group.items.forEach(item => {
                    let descHtml = applyTooltips(item.desc, versionId);
                    listHtml += `
                        <li>
                            <div class="dis-desc">${descHtml}</div>
                            <div class="dis-rate" style="font-weight:700; color:#dc2626;">${item.rate}</div>
                        </li>
                    `;
                });
                gradesHtml += `
                    <div class="accordion-item" id="acc-${index}">
                        <div class="accordion-header" onclick="toggleAccordion(${index})">
                            ${group.category}
                            <span class="material-icons-round">expand_more</span>
                        </div>
                        <div class="accordion-body">
                            <ul class="disability-list">
                                ${listHtml}
                            </ul>
                        </div>
                    </div>
                `;
            });
            container.innerHTML = gradesHtml;
        }

        // 2. 부위별 렌더링

        // 2. 부위별 아코디언 렌더링
        let partsHtml = '';
        if (data.parts) {
            data.parts.forEach((part, index) => {
                let pListHtml = '';
                part.items.forEach(item => {
                    let descHtml = applyTooltips(item.desc, versionId);
                    pListHtml += `
                        <li>
                            <div class="dis-desc">${descHtml}</div>
                            <div class="dis-rate" style="font-weight:700; color:#dc2626;">${item.rate}</div>
                        </li>
                    `;
                });
                
                // 관련 해설 박스
                let expBoxHtml = '';
                if (part.expIndices && part.expIndices.length > 0) {
                    expBoxHtml = '<div class="part-exp-box"><div class="part-exp-title">관련 장해 해설</div>';
                    part.expIndices.forEach(eIdx => {
                        const expData = data.explanations[eIdx];
                        if (expData) {
                            expBoxHtml += `
                                <div class="part-exp-item">
                                    <div class="part-exp-item-title">${expData.title}</div>
                                    <div class="part-exp-item-content">${formatExplanationContent(expData.content)}</div>
                                </div>
                            `;
                        }
                    });
                    expBoxHtml += '</div>';
                }

                partsHtml += `
                    <div class="accordion-item" id="part-acc-${index}">
                        <div class="accordion-header" onclick="document.getElementById('part-acc-${index}').classList.toggle('open')">
                            ${part.category}
                            <span class="material-icons-round">expand_more</span>
                        </div>
                        <div class="accordion-body">
                            <ul class="disability-list">
                                ${pListHtml}
                            </ul>
                            ${expBoxHtml}
                        </div>
                    </div>
                `;
            });
            document.getElementById('disability-parts').innerHTML = partsHtml;
        }

        // 3. 해설 카드 렌더링
        let expHtml = '';
        data.explanations.forEach((exp, index) => {
            expHtml += `
                <div class="exp-card" id="exp-${index}">
                    <div class="exp-title">${exp.title}</div>
                    <div class="exp-content">${exp.content}</div>
                </div>
            `;
        });
        expContainer.innerHTML = expHtml;

    } else {
        // 기존 신체부위별 렌더링 (v1804 등)
        tabs.classList.add('hidden');
        expContainer.classList.add('hidden');
        container.classList.remove('hidden');
        desc.classList.remove('hidden');
        desc.textContent = "원하시는 신체 부위를 선택하시면 상세 장해 상태와 지급률(%)을 확인하실 수 있습니다.";

        let html = '';
        data.forEach((group, index) => {
            let listHtml = '';
            group.items.forEach(item => {
                let descHtml = applyTooltips(item.desc, versionId);
                listHtml += `
                    <li>
                        <div class="dis-desc">${descHtml}</div>
                        <div class="dis-rate">${item.rate}</div>
                    </li>
                `;
            });

            html += `
                <div class="accordion-item" id="acc-${index}">
                    <div class="accordion-header" onclick="toggleAccordion(${index})">
                        ${group.category}
                        <span class="material-icons-round">expand_more</span>
                    </div>
                    <div class="accordion-body">
                        <ul class="disability-list">
                            ${listHtml}
                        </ul>
                    </div>
                </div>
            `;
        });
        container.innerHTML = html;
    }
    
    // 렌더링 후 장해분류표 화면으로 이동
    navigateTo('view-disability-table');
}

